#include <stdio.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N, X; scanf("%d %d", &N, &X);
        static char s[200005]; scanf("%s", s);
        int rem = 0;
        int ok = 1;
        for (int i = 0; i < N; ++i) {
            if (s[i] == '1') {
                rem = X;
            } else { // '0'
                if (rem == 0) { ok = 0; break; }
                rem--;
            }
        }
        printf(ok ? "YES\n" : "NO\n");
    }
    return 0;
}

