    int T; if(!(cin>>T)) return 0;
    while(T--) {
        int N, X; cin>>N>>X;
        string s; cin>>s;
        int rem = 0; bool ok = true;
        for(char c: s) {
            if(c=='1') rem = X;
            else {
                if(rem==0) { ok = false; break; }
                --rem;
            }
        }
        cout << (ok?"YES":"NO") << '\n';
    }
    return 0;
}

