import sys

def solve():
    data = sys.stdin.read().split()
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); X = int(next(it))
        s = next(it).strip()
        rem = 0
        ok = True
        for ch in s:
            if ch == '1':
                rem = X
            else:
                if rem == 0:
                    ok = False
                    break
                rem -= 1
        out_lines.append('YES' if ok else 'NO')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

